import "./tarjeta.css";

function Tarjeta(props) {
  return (
    <div className="tarjeta">
      <img src={props.ruta} alt={props.titulo} />
      <div className="texto-tarjeta">
        <h3>{props.titulo}</h3>
        <p>{props.precio}</p>
        <button>Ver Mas</button>
      </div>
    </div>
  );
};

export default Tarjeta;
